def count_with_k_ones(x, k):
    """Count numbers from 0 to x with exactly k ones in binary"""
    if x < 0:
        return 0

    binary = bin(x)[2:]
    n = len(binary)

    # dp[pos][ones][tight] = count of numbers
    memo = {}

    def dp(pos, ones, tight):
        if ones > k:
            return 0
        if pos == n:
            return 1 if ones == k else 0

        if (pos, ones, tight) in memo:
            return memo[(pos, ones, tight)]

        limit = int(binary[pos]) if tight else 1
        result = 0

        for digit in range(0, limit + 1):
            new_tight = tight and (digit == limit)
            result += dp(pos + 1, ones + digit, new_tight)

        memo[(pos, ones, tight)] = result
        return result

    return dp(0, 0, True)

def count_in_range(a, b, k):
    """Count numbers in [a, b] with exactly k ones in binary"""
    return count_with_k_ones(b, k) - count_with_k_ones(a - 1, k)

