def matches_pattern(filename, pattern):
    # Convert pattern to regex-like matching
    # We need to match filename against pattern where * matches zero or more characters

    def match(f_idx, p_idx):
        # Base cases
        if p_idx == len(pattern):
            return f_idx == len(filename)

        if pattern[p_idx] == '*':
            # Try matching 0 or more characters
            # First try matching 0 characters (skip the *)
            if match(f_idx, p_idx + 1):
                return True
            # Then try matching 1 or more characters
            if f_idx < len(filename):
                if match(f_idx + 1, p_idx):
                    return True
            return False
        else:
            # Regular character must match exactly
            if f_idx < len(filename) and filename[f_idx] == pattern[p_idx]:
                return match(f_idx + 1, p_idx + 1)
            return False

    return match(0, 0)

