        if i == 1:
            return x
        if i in memo:
            return memo[i]

        result = float('inf')

        # Option 1: Add one letter from i-1
        result = min(result, dp(i-1) + x)

        # Option 2: Copy from i//2 and adjust
        if i % 2 == 0:
            # i is even: copy from i/2
            result = min(result, dp(i // 2) + y)
        else:
            # i is odd: copy from (i+1)/2 and delete 1, or copy from (i-1)/2 and add 1
            result = min(result, dp((i + 1) // 2) + y + x)  # copy (i+1)/2 then delete
            result = min(result, dp((i - 1) // 2) + y + x)  # copy (i-1)/2 then add

        memo[i] = result
        return result

    return dp(n)

