    def find_path(start):
        if start == N:
            return [N]

        queue = deque([(start, [start])])
        visited = {start}

        while queue:
            node, path = queue.popleft()

            for next_node in graph[node]:
                if next_node not in visited:
                    new_path = path + [next_node]
                    if next_node == N:
                        return new_path
                    visited.add(next_node)
                    queue.append((next_node, new_path))

        return None

    # Get paths for all producers
    paths = {}
    for j in range(1, K + 1):
        path = find_path(j)
        if path:
            paths[j] = path

    if not paths:
        print(0)
        return

    # Check if two producers conflict
    def conflicts(prod_i, prod_j):
        path_i = paths[prod_i]
        path_j = paths[prod_j]

        # For each edge in path_i, check if it conflicts with path_j
        # Product from prod_i at time x*K + prod_i uses edges at times:
        # x*K + prod_i + step_number (for step_number = 0, 1, 2, ...)

        # Check a reasonable time window
        for x in range(K * 100):  # Check first K*100 products
            time_i = x * K + prod_i
            for step, (u, v) in enumerate(zip(path_i[:-1], path_i[1:])):
