                        edge_time_j = time_j + step_j
                        if (u, v) == (u_j, v_j) and edge_time_i == edge_time_j:
                            return True

        return False

    # Find maximum independent set
    active_producers = list(paths.keys())
    max_count = 0

    # Try all subsets
