def solve(A, C, M):
    MOD = 10**9 + 7

    # dp[a][c][m][last] where last: 0=apple, 1=cherry, 2=mango
    dp = [[[[0 for _ in range(3)] for _ in range(M+1)] for _ in range(C+1)] for _ in range(A+1)]

    # Base cases - single fruit
    if A > 0:
        dp[1][0][0][0] = 1
    if C > 0:
        dp[0][1][0][1] = 1
    if M > 0:
        dp[0][0][1][2] = 1

    # Fill DP table
    for total in range(1, A+C+M+1):
        for a in range(min(A, total)+1):
            for c in range(min(C, total-a)+1):
                m = total - a - c
                if m < 0 or m > M:
                    continue
                if a == 0 and c == 0 and m == 0:
                    continue

                # Last fruit is apple
                if a > 0:
                    dp[a][c][m][0] = (dp[a-1][c][m][1] + dp[a-1][c][m][2]) % MOD

                # Last fruit is cherry
                if c > 0:
                    dp[a][c][m][1] = (dp[a][c-1][m][0] + dp[a][c-1][m][2]) % MOD

                # Last fruit is mango
                if m > 0:
                    dp[a][c][m][2] = (dp[a][c][m-1][0] + dp[a][c][m-1][1]) % MOD

    result = (dp[A][C][M][0] + dp[A][C][M][1] + dp[A][C][M][2]) % MOD
    return result

