def modinv(a, m=MOD):
    return pow(a, m-2, m)

def comb(n, r, mod=MOD):
    if r > n or r < 0:
        return 0
    if r == 0 or r == n:
        return 1

    num = 1
    den = 1
    for i in range(r):
        num = (num * (n - i)) % mod
        den = (den * (i + 1)) % mod

    return (num * modinv(den, mod)) % mod

