    def has_black_edge(start, end):
        if start == end:
            return False

        # DFS to find path
        visited = set()

        def dfs(node, target, has_black):
            if node == target:
                return has_black

            visited.add(node)
            for neighbor, color in graph[node]:
                if neighbor not in visited:
                    result = dfs(neighbor, target, has_black or (color == 1))
                    if result is not None:
                        return result

            return None

        result = dfs(start, end, False)
        return result if result is not None else False

    # Build red-only connectivity matrix
    red_only = [[False] * (n + 1) for _ in range(n + 1)]
    for i in range(1, n + 1):
        for j in range(1, n + 1):
            if not has_black_edge(i, j):
                red_only[i][j] = True

    # DP: dp[i][v] = number of sequences of length i ending at vertex v using only red edges
    dp = [[0] * (n + 1) for _ in range(k + 1)]

    # Base case: sequences of length 1
    for v in range(1, n + 1):
        dp[1][v] = 1

    # Fill DP table
    for i in range(1, k):
        for v in range(1, n + 1):
            if dp[i][v] > 0:
                for u in range(1, n + 1):
                    if red_only[v][u]:
                        dp[i + 1][u] = (dp[i + 1][u] + dp[i][v]) % MOD

    # Count bad sequences (all red edges)
    bad_sequences = sum(dp[k][v] for v in range(1, n + 1)) % MOD

    # Total sequences
    total_sequences = pow(n, k, MOD)

    # Good sequences
    good_sequences = (total_sequences - bad_sequences + MOD) % MOD

    print(good_sequences)

