def solve(x):
    if x == 0:
        return (1, 1)

    # Find factors of x
    # x = n² - k² = (n-k)(n+k)
    # Let a = n-k, b = n+k where a ≤ b
    # Then n = (a+b)/2, k = (b-a)/2

    for a in range(1, int(x**0.5) + 2):
        if x % a == 0:
            b = x // a
            if (a + b) % 2 == 0:  # n must be integer
                n = (a + b) // 2
                k = (b - a) // 2

                if k == 0:  # k must be at least 1 for m to exist
                    continue

                # Find m such that floor(n/m) = k
                # We need k <= n/m < k+1
                # So n/(k+1) < m <= n/k
                m = n // k

                if m >= 1 and n // m == k:
                    return (n, m)

    return None

